for idx, grpc_msg_encoded in enumerate(grpc_msg_test_list):
    grpc_msg_bytes = bytes.fromhex(grpc_msg_encoded)
    grpc_msg_decompress: bytes = gzip.decompress(grpc_msg_bytes[5:])
    # grpc_msg_hex: str = grpc_msg_decompress.hex()
    # print(f'正确的proto消息hex类型：{grpc_msg_hex}')
    # grpc_msg_decoded = base64.b64encode(grpc_msg_decompress).decode('utf-8')
    # print(f'正确的proto消息base64类型：{grpc_msg_decoded}')
    # grpc_msg: bytes = base64.b64decode(grpc_msg_decoded)
    # print(f'正确的proto消息bytes类型：{grpc_msg}')
    raw_data, typedef = protoc_decode_raw(grpc_msg_decompress)
    print(json.dumps(json.loads(raw_data),ensure_ascii=False))
    msg = dynamic_pb2.DynDetailReply()
    try:
        msg.ParseFromString(
            grpc_msg_decompress
        )
    except Exception as e:
        print(f'第{idx}条消息解析失败：{e}')
    resp_dict = MessageToDict(msg)
    print(f'解码后的proto消息：{json.dumps(resp_dict,ensure_ascii=False)}')
